"use client";

import { cn } from "../../lib/utils";
import type { Variants } from "motion/react";
import {
 LazyMotion,
 domMin,
 m,
 useAnimation,
 useReducedMotion,
} from "motion/react";
import {
 forwardRef,
 useCallback,
 useImperativeHandle,
 useRef,
 type HTMLAttributes,
} from "react";
export interface TerminalIconHandle {
 startAnimation: () => void;
 stopAnimation: () => void;
}

interface TerminalIconProps extends Omit<
 HTMLAttributes<HTMLDivElement>,
 | "color"
 | "onDrag"
 | "onDragStart"
 | "onDragEnd"
 | "onAnimationStart"
 | "onAnimationEnd"
 | "onAnimationIteration"
> {
 size?: number;
 duration?: number;
 isAnimated?: boolean;
 color?: string;
}

const TerminalIcon = forwardRef<TerminalIconHandle, TerminalIconProps>(
 (
  {
   onMouseEnter,
   onMouseLeave,
   className,
   size = 24,
   duration = 1,
   isAnimated = true,
   color,
   ...props
  },
  ref,
 ) => {
  const controls = useAnimation();
  const reduced = useReducedMotion();
  const isControlled = useRef(false);

  useImperativeHandle(ref, () => {
   isControlled.current = true;
   return {
    startAnimation: () =>
     !isAnimated || reduced ? controls.start("normal") : controls.start("animate"),
    stopAnimation: () => controls.start("normal"),
   };
  });

  const handleEnter = useCallback(
   (e?: React.MouseEvent<HTMLDivElement>) => {
    if (!isAnimated || reduced) return;
    if (!isControlled.current) controls.start("animate");
    else onMouseEnter?.(e as any);
   },
   [controls, reduced, isAnimated, onMouseEnter],
  );

  const handleLeave = useCallback(
   (e?: React.MouseEvent<HTMLDivElement>) => {
    if (!isControlled.current) controls.start("normal");
    else onMouseLeave?.(e as any);
   },
   [controls, onMouseLeave],
  );

  const svgVariants: Variants = {
   normal: { transition: { duration: 0.3 * duration } },
   animate: { transition: { staggerChildren: 0.1 } },
  };

  const commandLineVariants: Variants = {
   normal: {
    scaleX: 1,
    originX: 0,
    transition: { duration: 0.3 * duration },
   },
   animate: {
    scaleX: [1, 0.3, 1],
    originX: 0,
    transition: { duration: 0.6 * duration, times: [0, 0.5, 1], repeat: 0 },
   },
  };

  const chevronVariants: Variants = {
   normal: { x: 0, opacity: 1 },
   animate: {
    x: [0, -2, 0],
    opacity: [1, 0.6, 1],
    transition: { duration: 0.5 * duration, repeat: 0 },
   },
  };

  return (
   <LazyMotion features={domMin} strict>
    <m.div
     className={cn("inline-flex items-center justify-center", className)}
     onMouseEnter={handleEnter}
     onMouseLeave={handleLeave}
     {...props}
     style={{ color, ...props.style }}
    >
     <m.svg
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      variants={svgVariants}
      animate={controls}
      initial="normal"
     >
      <m.path d="M12 19h8" variants={commandLineVariants} />
      <m.path d="m4 17 6-6-6-6" variants={chevronVariants} />
     </m.svg>
    </m.div>
   </LazyMotion>
  );
 },
);

TerminalIcon.displayName = "TerminalIcon";
export { TerminalIcon };

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
	return twMerge(clsx(inputs));
}
